package com.example.banking.security;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import org.apache.wss4j.common.ext.WSPasswordCallback;

public class ServerKeystorePasswordCallback implements CallbackHandler {
    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        if (callbacks == null) {
            return;
        }
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                if ("bankserver".equals(pc.getIdentifier())) {
                    pc.setPassword("changeit");
                }
            }
        }
    }
}

package com.example.banking.publisher;

import com.example.banking.config.SecurityPropertiesFactory;
import com.example.banking.security.SignatureVerificationAuditInterceptor;
import com.example.banking.security.SignedElementsCaptureInInterceptor;
import com.example.banking.service.BankingServiceImpl;
import org.apache.cxf.endpoint.Server;
import org.apache.cxf.frontend.ServerFactoryBean;
import org.apache.cxf.transport.servlet.CXFServlet;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;

import javax.servlet.Servlet;
import java.util.Properties;

public class BankingServicePublisher {

    public Server publish(String address) {
        ServerFactoryBean factory = new ServerFactoryBean();
        factory.setServiceClass(BankingServiceImpl.class);
        factory.setAddress(address);
        factory.getInInterceptors().add(new SignedElementsCaptureInInterceptor());

        Properties wssIn = SecurityPropertiesFactory.serverInProperties();
        factory.getInInterceptors().add(new WSS4JInInterceptor(wssIn));
        factory.getInInterceptors().add(new SignatureVerificationAuditInterceptor());

        return factory.create();
    }

    public Servlet cxfServlet() {
        return new CXFServlet();
    }

    public static void main(String[] args) {
        new BankingServicePublisher().publish("http://0.0.0.0:8080/services/BankingService");
    }
}

